import React from 'react';
import './Welcome.css'
import './AddForm.css';
import axios from 'axios';
import { useFormik } from 'formik';
import { useNavigate } from 'react-router';

function AddForm () {

    // const navigate = useNavigate();

    const validate = values => {
        const errors = {}

        if (!values.userName) {
            errors.userName = 'Required'
        }
        if (!values.targetDate) {
            errors.targetDate = 'Required'
        }
        if (!values.isDone) {
            errors.isDone = 'Required'
        }
        return errors;
    }
    const formik = useFormik({
        initialValues: {

            userName: '',
            targetDate: '',
            isDone: ''
        },
        validate,
        onSubmit: values =>
            axios ({
                method: "POST",
                url: "http://localhost:8080/users/Admin/items",
                data: values
            }).then(response => {
                console.log(response);
                // navigate('/Welcome')
            }).catch(err => {console.log(err)})
    })

    // navigate('/Welcome');
// Add REGEX for Password strength and e-amil
    return (
        <div>
            <h1>Add An Item, Stay Productiv!</h1>
            <form className='location-form' onSubmit={formik.handleSubmit}>
                <div>
                <label htmlFor='userName'> Description </label>
                <input className='input-fields' onChange={formik.handleChange} value = {formik.values.userName} onBlur = {formik.handleBlur} type='text' id='userName' name = 'userName'/>
                {formik.touched.userName && formik.errors.userName ? <div>{formik.errors.userName}</div> : null}
                </div>
                <div>
                <label htmlFor='date'> Date </label>
                <input className='input-fields' onChange={formik.handleChange} value = {formik.values.targetDate} onBlur = {formik.handleBlur} type='text' id='targetDate' name = 'targetDate'/>
                {formik.touched.targetDate && formik.errors.targetDate ? <div>{formik.errors.targetDate}</div> : null}
                </div>
                <div>
                <label htmlFor='isDone'> Status </label>
                <input className='input-fields' onChange={formik.handleChange} value = {formik.values.isDone} onBlur = {formik.handleBlur} type='text' id='isDone' name = 'isDone'/>
                {formik.touched.isDone && formik.errors.isDone ? <div>{formik.errors.isDone}</div> : null}
                </div>
                <button type='submit' className='add-form-button'>Submit</button>
                <button type='cancel' className='cancel-form-button' onClick={navigate('/Welcome')}>Cancel</button>
            </form>
        </div>
    )
}

export default AddForm;
